import{_ as e,o as t,c as o,ag as r}from"./chunks/framework.DXGyWiRo.js";const c=JSON.parse('{"title":"1988年巴菲特致股东的信核心总结","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1988年/核心总结.md","filePath":"01_letters/1988年/核心总结.md"}'),l={name:"01_letters/1988年/核心总结.md"};function i(h,a,n,p,s,d){return t(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="_1988年巴菲特致股东的信核心总结" tabindex="-1">1988年巴菲特致股东的信核心总结 <a class="header-anchor" href="#_1988年巴菲特致股东的信核心总结" aria-label="Permalink to &quot;1988年巴菲特致股东的信核心总结&quot;">​</a></h1><h2 id="简要导读" tabindex="-1">简要导读 <a class="header-anchor" href="#简要导读" aria-label="Permalink to &quot;简要导读&quot;">​</a></h2><p>1988年巴菲特第一次买可口可乐，在这封信里，巴菲特再次讲透了他为什么买入好企业就拿着不卖，为什么只集中持有少数你懂的好公司。同时也把公司治理里CEO考核不称职的问题讲得一针见血，非常值得读。文末可下载英文原版PDF。</p><h2 id="一、会计不会告诉你真实价值-管理者有义务告诉你真话" tabindex="-1">一、会计不会告诉你真实价值，管理者有义务告诉你真话 <a class="header-anchor" href="#一、会计不会告诉你真实价值-管理者有义务告诉你真话" aria-label="Permalink to &quot;一、会计不会告诉你真实价值，管理者有义务告诉你真话&quot;">​</a></h2><p>巴菲特说，GAAP会计准则要求你合并所有子公司，合并完了，一堆不同业务混在一起，投资者什么都看不出来，所以我们主动给你分四块报告：金融保险，保险，制造零售出版，非营业资产，这样你自己就能算，我们真正值多少钱，经理干得好不好，能不能还债，三个问题你自己就能回答。</p><p>很多管理者本来就故意用GAAP骗你，&quot;你想要多少，会计师就能给你出多少&quot;，很多造假就是合法利用GAAP，投资者一定要小心，&quot;拿笔偷大钱，比拿枪抢安全多了&quot;。</p><h2 id="二、好生意-好管理层-就是不断创造高roe-我们放手让他们干" tabindex="-1">二、好生意，好管理层，就是不断创造高ROE，我们放手让他们干 <a class="header-anchor" href="#二、好生意-好管理层-就是不断创造高roe-我们放手让他们干" aria-label="Permalink to &quot;二、好生意，好管理层，就是不断创造高ROE，我们放手让他们干&quot;">​</a></h2><p>巴菲特说，我们七个全资好生意，没有杠杆，平均ROE 67%，你没看错就是67%，这就是为什么我们内在价值增长这么快，这些生意本来就有好特许权，加上好管理层，我们就是放手让他们干，我们不干预，我们贡献就是鼓掌，所以他们能干得更好。</p><p>例子：</p><ul><li>95岁B夫人还在干活，NFM越做越大，Dillard进奥马哈都不敢卖家具和她竞争</li><li>水牛城新闻，巴菲特去年说利润率一定会降，结果斯坦·利普西就是做到利润率不降，还保持50%新闻版面，给读者最多新闻</li><li>喜诗糖果，查克·哈金斯，年年创纪录，圣诞占利润90%，依然做得很好</li></ul><p>我们新收购Borsheim珠宝，也是家族生意，还是布鲁姆金家族分支，一样的做生意方法：低价卖，说实话，巨大库存给你最多选择，快速周转，精明采购，低费用，所以能给消费者最低价，消费者自然用脚投票，生意越来越好，和NFM一模一样，这就是家族生意优势，我们买过来就是让他们继续干，我们不插手。</p><h2 id="三、保险行业-价格不对我们就不做-宁愿闲着" tabindex="-1">三、保险行业：价格不对我们就不做，宁愿闲着 <a class="header-anchor" href="#三、保险行业-价格不对我们就不做-宁愿闲着" aria-label="Permalink to &quot;三、保险行业：价格不对我们就不做，宁愿闲着&quot;">​</a></h2><p>巴菲特还是那个结论：财险行业每年损失增长大约10%，保费增长跟不上，承保损失一定会越来越大，1988年保费增长只有3.9%，所以损失肯定继续涨。公众对行业特别不满意，因为价格涨了大家生气，好价格好利润的时候已经过去了。</p><p>我们就是这个态度：价格不对我们就不做，所以保费越来越少，但是我们利润比行业好，我们浮存金还很多，足够用，等着别人出问题，价格涨了我们再做，现在就是等着，不做错事。</p><p>加州103提案，要求强制压低汽车保险价格，对GEICO影响大，GEICO就是低成本领导者，价格压到低于成本，GEICO多年建立的品牌价值就没了，所以对我们影响很大。</p><h2 id="四、投资-我们喜欢拿着好公司-永远不卖" tabindex="-1">四、投资：我们喜欢拿着好公司，永远不卖 <a class="header-anchor" href="#四、投资-我们喜欢拿着好公司-永远不卖" aria-label="Permalink to &quot;四、投资：我们喜欢拿着好公司，永远不卖&quot;">​</a></h2><p>巴菲特说，我们1988年买了可口可乐和房地美，都是好公司好管理层，我们打算长期拿着，我们就是这个态度：&quot;我们买了杰出企业杰出管理层，我们最喜欢持有期限就是永远&quot;。我们就是反过来：表现好赶紧卖赚差价，表现差死拿着，彼得林奇说这就是&quot;剪花浇草&quot;，我们完全同意。</p><p>我们就喜欢集中持有少数我们真懂的好公司，我们同意梅·韦斯特说的：&quot;好东西越多越好&quot;。太多好东西，比没有好。</p><p>巴菲特还是那个老观点：我们不喜欢长期债券，我们不相信美元长期购买力稳定，所以长期债券我们就是不碰，除非价格特别错杀，我们才会买一点，WPPSS就是这样，结果赚了钱，我们还是不喜欢长期债券。</p><h2 id="五、公司治理-为什么不合格ceo总是不会被炒" tabindex="-1">五、公司治理：为什么不合格CEO总是不会被炒？ <a class="header-anchor" href="#五、公司治理-为什么不合格ceo总是不会被炒" aria-label="Permalink to &quot;五、公司治理：为什么不合格CEO总是不会被炒？&quot;">​</a></h2><p>巴菲特说，很有意思一个对比：秘书打字不够快马上走人，销售卖不出货马上走人，但是CEO不行，业绩不好位置还特别稳，为什么？</p><ul><li>秘书销售业绩容易衡量，不合格马上就能看出来，不合格马上走。</li><li>CEO业绩衡量标准模糊，就算不合格，也很难说，董事会也不愿意批评，老板就是老板，谁也不说。</li></ul><p>所以我们太幸运了，我们三大重仓，管理层都是真·所有者，热爱自己公司，诚信能力都够，我们太幸运了。</p><h2 id="六、股息政策-我们不分红不拆股-就是为了股东好" tabindex="-1">六、股息政策：我们不分红不拆股，就是为了股东好 <a class="header-anchor" href="#六、股息政策-我们不分红不拆股-就是为了股东好" aria-label="Permalink to &quot;六、股息政策：我们不分红不拆股，就是为了股东好&quot;">​</a></h2><p>巴菲特说，我们过去二十年不分红，因为我们把赚的钱再投资，能帮股东增加更多每股内在价值，比分红给你，你自己交税再投资更好，所以我们不分红，我们也不拆股，拆股增加交易成本，吸引短线交易者，更容易让股价偏离内在价值，我们想要长线股东，我们现在股东群体非常好，我们不想换。</p><h2 id="七、核心启示" tabindex="-1">七、核心启示 <a class="header-anchor" href="#七、核心启示" aria-label="Permalink to &quot;七、核心启示&quot;">​</a></h2><ol><li>投资者自己有权知道真话，CEO不能只给你GAAP报表，就不管了，优秀管理者应该帮你看清楚，真实价值到底多少。</li><li>好家族生意，好经理人，放手让他们干，不要瞎指挥，少做事，做对事，比多做事更重要。</li><li>保险行业不对就不做，宁愿闲着，价格不对不接单，这才是长期生存之道。</li><li>买了好公司，就拿着别动，集中持有少数你懂的好公司，比换来换去赚得多。</li></ol><hr><blockquote><p>📎 <strong>文末小惊喜</strong>：可点击下载<a href="Chairman&#39;s%20Letter%20-%20%201988.pdf">巴菲特1988年股东信原件PDF</a>，原汁原味阅读英文原文。</p></blockquote>',29)])])}const q=e(l,[["render",i]]);export{c as __pageData,q as default};
